+            "INSERT INTO agents
+             (id, project_id, name, program, model, task_description, inception_ts, last_active_ts, attachments_policy, contact_policy)
+             VALUES (1, 1, 'BlueForest', 'codex-cli', 'gpt-5', 'doctor test', 0, 0, 'auto', 'auto')",
+        )
+        .expect("insert agent");
